import { Translations, Locale } from './types.js';
import { I18nValues } from './values.js';
import { notify } from './middleware/notify.js';

type PrimitiveType = boolean | number | string;
type NotifyFunc = typeof notify;

type I18nOptions = {
    /**
     * All downloaded translations to be used.
     */
    translations: Translations;
    /**
     * Locale provided to notify when a translation is missing.
     *
     * @example 'es-AR'
     */
    locale?: Locale;
    /**
     * Flag provided when you need to send metrics for missing translations.
     */
    notifyMissingTranslations?: boolean;
    /**
     * Custom notification function on missing translation.
     */
    notify?: NotifyFunc;
};
declare class I18n {
    #private;
    constructor(options: I18nOptions);
    get locale(): Locale | undefined;
    get translations(): Translations;
    /**
     * Given a text, returns the translation.
     *
     * @example
     * getTranslation('Mi mensaje');
     * // My message
     */
    getTranslation(text: string, msgctxt?: string): string;
    /**
     * Given a text and a quantity, returns the translation of the text depending on whether it is singular or plural.
     *
     * @example
     * getPluralTranslation('You have {0} message', 'You have {0} messages', 3);
     * // You have 3 messages'
     */
    getPluralTranslation(singularText: string, pluralText: string, quantity: number, context?: string): string;
    /**
     * Given a text, return the translation with its arguments replaced.
     *
     * @param text Text key to search in translations.
     * @param replacements Replacement strings to inject into text.
     * @return The text translated and replaced.
     *
     * @example
     * gettext('This is {0}, right {0}?', ['John'])
     * // This is John, right John?
     */
    gettext(text: string, ...replacements: Array<PrimitiveType> | [Array<PrimitiveType>] | [I18nValues]): string;
    /**
     * Given a text in singular, a text in plural and a quantity, return the translation with its arguments replaced.
     *
     * @param singularText Singular text key to search in translations.
     * @param pluralText Plural text key to search in translations.
     * @param quantity Number to determine if singular or plural text should be used.
     * @param replacements Replacement strings to inject into text.
     * @return The text translated and replaced.
     *
     * @example
     * ngettext('{0}, You have {1} message', '{0}, You have {1} messages', 6, ['John', 6])
     * // John, You have 6 messages
     */
    ngettext(singularText: string, pluralText: string, quantity: number, ...replacements: Array<PrimitiveType> | [Array<PrimitiveType>] | [I18nValues]): string;
    /**
     * Given a context and a text, return the translation with its arguments replaced.
     *
     * @param context The context in which this text will be displayed.
     * @param text Text key to search in translations.
     * @param replacements Replacement strings to inject into text.
     * @return The text translated and replaced.
     *
     * @example
     * pgettext('question', This is {0}, right {0}?', ['John'])
     * // This is John, right John?
     */
    pgettext(context: string, text: string, ...replacements: Array<PrimitiveType> | [Array<PrimitiveType>] | [I18nValues]): string;
    /**
     * Given a context, a text in singular, a text in plural and a quantity, return the translation with its arguments replaced.
     *
     * @param context The context in which this text will be displayed.
     * @param singularText Singular text key to search in translations.
     * @param pluralText Plural text key to search in translations.
     * @param quantity Number to determine if singular or plural text should be used.
     * @param replacements Replacement strings to inject into text.
     * @return The text translated and replaced.
     *
     * @example
     * npgettext('information', {0}, You have {1} message', '{0}, You have {1} messages', 6, ['John', 6])
     * // John, You have 6 messages
     */
    npgettext(context: string, singularText: string, pluralText: string, quantity: number, ...replacements: Array<PrimitiveType> | [Array<PrimitiveType>] | [I18nValues]): string;
}

export { I18n, Locale, Translations };
export type { I18nOptions };
